sql:
SELECT t.trainer_name, p.pokemon_name, t.battle_wins AS max_battles_won
FROM trainers t
JOIN pokemon p ON t.trainer_id = p.trainer_id
WHERE t.battle_wins = (
    SELECT MAX(battle_wins) FROM trainers
);

SELECT pokemon_id, COUNT(move_id) AS total_moves
FROM pokemon_moves
GROUP BY pokemon_id;

SELECT category_name, description
FROM move_categories
WHERE category_name LIKE 'A%';

SELECT AVG(pp_max)
FROM pokemon_moves
WHERE pokemon_id = 0;

SELECT pokemon.pokemon_name, trainers.trainer_name
FROM pokemon
INNER JOIN trainers ON pokemon.trainer_id = trainers.trainer_id;

SELECT moves.move_name, move_types.type_name
FROM moves
JOIN move_types ON moves.type_id = move_types.type_id;
